import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.BuL2a98s.js";const u=JSON.parse('{"title":"Preparar el entorno","description":"","frontmatter":{},"headers":[],"relativePath":"guide/entorno.md","filePath":"guide/entorno.md"}'),n={name:"guide/entorno.md"};function r(o,a,l,p,d,c){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="preparar-el-entorno" tabindex="-1">Preparar el entorno <a class="header-anchor" href="#preparar-el-entorno" aria-label="Permalink to &quot;Preparar el entorno&quot;">​</a></h1><p>Esta guía prepara la computadora para descargar y abrir los ejemplos del repositorio:</p><p><a href="https://github.com/UNIT-Electronics-Labs/unit_devlab_fpga_examples" target="_blank" rel="noreferrer">UNIT-Electronics-Labs/unit_devlab_fpga_examples</a></p><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><p>Instala las siguientes herramientas antes de continuar:</p><ul><li><a href="https://code.visualstudio.com/download" target="_blank" rel="noreferrer">Visual Studio Code</a>, para editar y usar la terminal integrada.</li><li><a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">Python 3.11 o posterior</a>, requerido por DevLab.</li><li><a href="https://git-scm.com/downloads" target="_blank" rel="noreferrer">Git</a>, recomendado para descargar y actualizar los ejemplos.</li></ul><p>En Windows, activa la opción <strong>Add Python to PATH</strong> durante la instalación de Python. VS Code incluye integración con Git, pero Git debe instalarse por separado.</p><h3 id="requisito-adicional-para-windows-zadig" tabindex="-1">Requisito adicional para Windows: Zadig <a class="header-anchor" href="#requisito-adicional-para-windows-zadig" aria-label="Permalink to &quot;Requisito adicional para Windows: Zadig&quot;">​</a></h3><p>Para que DevLab pueda cargar el diseño en la FPGA desde Windows, también necesitas <a href="https://zadig.akeo.ie/" target="_blank" rel="noreferrer">Zadig</a>. Conecta la tarjeta, abre Zadig, activa <strong>Options → List All Devices</strong>, selecciona <strong>JTAG Debugger</strong> o <strong>USB-JTAG</strong> e instala el controlador <strong>WinUSB</strong> o <strong>libusbK</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Importante</p><p>Sin este controlador, <code>devlab flash</code> no podrá comunicarse con la FPGA. Consulta la <a href="./windows#_2-configurar-driver-usb-con-zadig">configuración detallada de Zadig</a>, que incluye capturas y todos los pasos.</p></div><h2 id="verificar-la-instalacion" tabindex="-1">Verificar la instalación <a class="header-anchor" href="#verificar-la-instalacion" aria-label="Permalink to &quot;Verificar la instalación&quot;">​</a></h2><p>Cierra y vuelve a abrir la terminal después de instalar las herramientas. En Windows ejecuta:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">code </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span></code></pre></div><p>En Linux ejecuta:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">code</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>Cada comando debe mostrar un número de versión. Si <code>code</code> no se reconoce, abre la carpeta desde <strong>Archivo → Abrir carpeta</strong> en VS Code.</p><h2 id="descargar-los-ejemplos" tabindex="-1">Descargar los ejemplos <a class="header-anchor" href="#descargar-los-ejemplos" aria-label="Permalink to &quot;Descargar los ejemplos&quot;">​</a></h2><p>El repositorio es público. Para descargarlo por HTTPS o como ZIP no necesitas una cuenta de GitHub ni credenciales.</p><table tabindex="0"><thead><tr><th>Método</th><th>¿Requiere credenciales?</th><th>¿Permite actualizar con Git?</th><th>Recomendado para</th></tr></thead><tbody><tr><td>HTTPS</td><td>No, para descargar este repositorio público</td><td>Sí</td><td>La mayoría de los estudiantes</td></tr><tr><td>SSH</td><td>Sí, requiere una llave SSH registrada en GitHub</td><td>Sí</td><td>Quien ya usa GitHub por SSH</td></tr><tr><td>ZIP</td><td>No</td><td>No</td><td>Obtener una copia sin instalar o usar Git</td></tr></tbody></table><h3 id="opcion-1-clonar-con-https-recomendada" tabindex="-1">Opción 1: clonar con HTTPS (recomendada) <a class="header-anchor" href="#opcion-1-clonar-con-https-recomendada" aria-label="Permalink to &quot;Opción 1: clonar con HTTPS (recomendada)&quot;">​</a></h3><p>Abre PowerShell, Git Bash o una terminal y ejecuta:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/UNIT-Electronics-Labs/unit_devlab_fpga_examples.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unit_devlab_fpga_examples</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>Más adelante puedes descargar cambios del repositorio con:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span></code></pre></div><p>GitHub solo solicitará autenticación si intentas enviar cambios o acceder a recursos privados.</p><h3 id="opcion-2-clonar-con-ssh" tabindex="-1">Opción 2: clonar con SSH <a class="header-anchor" href="#opcion-2-clonar-con-ssh" aria-label="Permalink to &quot;Opción 2: clonar con SSH&quot;">​</a></h3><p>Usa esta opción solamente si ya <a href="https://docs.github.com/es/authentication/connecting-to-github-with-ssh" target="_blank" rel="noreferrer">generaste una llave SSH y la agregaste a tu cuenta de GitHub</a>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com:UNIT-Electronics-Labs/unit_devlab_fpga_examples.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unit_devlab_fpga_examples</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>No es necesario crear una llave SSH para seguir el curso; HTTPS es suficiente.</p><h3 id="opcion-3-descargar-un-archivo-zip" tabindex="-1">Opción 3: descargar un archivo ZIP <a class="header-anchor" href="#opcion-3-descargar-un-archivo-zip" aria-label="Permalink to &quot;Opción 3: descargar un archivo ZIP&quot;">​</a></h3><ol><li>Abre el <a href="https://github.com/UNIT-Electronics-Labs/unit_devlab_fpga_examples" target="_blank" rel="noreferrer">repositorio en GitHub</a>.</li><li>Selecciona <strong>Code → Download ZIP</strong>.</li><li>Extrae el archivo en una carpeta de trabajo.</li><li>En VS Code selecciona <strong>Archivo → Abrir carpeta</strong> y abre <code>unit_devlab_fpga_examples-main</code>.</li></ol><p>Una copia ZIP no conserva el historial de Git y no se puede actualizar con <code>git pull</code>. Para recibir cambios tendrás que descargar un ZIP nuevo.</p><h2 id="preparar-vs-code" tabindex="-1">Preparar VS Code <a class="header-anchor" href="#preparar-vs-code" aria-label="Permalink to &quot;Preparar VS Code&quot;">​</a></h2><p>Abre <strong>Extensiones</strong> con <code>Ctrl + Shift + X</code> e instala la extensión oficial <strong>Python</strong>, publicada por Microsoft. De manera opcional, instala una extensión de sintaxis para Verilog y VHDL.</p><p>Después abre la terminal integrada con <strong>Terminal → Nueva terminal</strong>. Los comandos de compilación y carga se ejecutarán desde esta terminal.</p><h2 id="siguiente-paso" tabindex="-1">Siguiente paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente paso&quot;">​</a></h2><p>Con el repositorio abierto, continúa con la instalación correspondiente a tu sistema operativo:</p><ul><li><a href="./windows">Configurar Windows</a></li><li><a href="./linux">Configurar Linux</a></li></ul><p>Después consulta <a href="./devlab">Usar DevLab</a> para compilar y cargar un ejemplo en la FPGA.</p>`,39)])])}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
